using wrf::sdirk3::RhsMode;

// SPLIT-EXPLICIT D1 FIX (2026-07-11): when set, computeUnifiedRHS returns the COUPLED
// tendencies d(mu*X)/dt for u/v/w/theta (skipping the inverse-product-rule decouple) —
// WRF rk_tendency parity. The split driver's decouple(RHS-internal mu_tend)/recouple
// (native DMDT) round trip used TWO DIFFERENT mu tendencies; the residual
// X*(dmdt - mu_tend_RHS) is a w-activated spurious frozen tendency (measured ~x100/step
// growth, theta-weighted, upper-level). Set ONLY around the split driver's K_exp calls
// via CoupledSlowGuard; default false => baseline byte-identical.
static thread_local bool g_export_coupled_slow = false;
struct CoupledSlowGuard {
    CoupledSlowGuard() { g_export_coupled_slow = true; }
    ~CoupledSlowGuard() { g_export_coupled_slow = false; }
};

// WRF vertical order-3 advection tendency for a mass-level field (advect_scalar vertical
// section, namelist v_sca/mom_adv_order=3; module_advect_em.F): w-level fluxes
//   kf=1, nz-1:  vflux = Omega * (fzm*q(kf) + fzp*q(kf-1))     [stretch weights, NOT 0.5]
//   kf=2..nz-2:  vflux = Omega * flux3(q(kf-2..kf+1), ua=-Omega)
//     flux3 = flux4 + sign(ua)*((q_ip1-q_im2) - 3(q_i-q_im1))/12,
//     flux4 = (7(q_i+q_im1) - (q_ip1+q_im2))/12               [WRF :195-204 exact — NOT the
//     file's flux3_upwind helper, whose flux4 is a "simplified" deviation]
//   kf=0, nz: zero boundary fluxes.
// tendency(k=0..nz-1) = +|rdnw(k)| * (vflux(k+1)-vflux(k))  [WRF passes NEGATIVE rdnw as
// rdzw and writes tendency -= rdzw*d, module_em.F:630] — INCLUDING the top mass level.
// fzm/fzp from |dnw|/|dn| (module_initialize_ideal.F:730-734; 0-based: fzm[kf-1] =
// .5*dnw0[kf-1]/dn0[kf], fzp[kf-1] = .5*dnw0[kf]/dn0[kf]; sum == 1). Omega is WRF-signed.
static torch::Tensor wrf_vert_adv3(const torch::Tensor& q, const torch::Tensor& omega,
                                   const torch::Tensor& rdnw_pos, const torch::Tensor& rdn_pos,
                                   float sign_delta) {
    const int64_t nz = q.size(1);
    auto dnw = torch::reciprocal(rdnw_pos.slice(0, 0, nz));                 // |dnw0|, {nz}
    auto dnv = torch::reciprocal(rdn_pos.slice(0, 1, nz));                  // |dn0[1..nz-1]|
    auto fzm = (0.5f * dnw.slice(0, 0, nz - 1) / dnv).view({1, nz - 1, 1}); // idx kf-1
    auto fzp = (0.5f * dnw.slice(0, 1, nz) / dnv).view({1, nz - 1, 1});
    // interior w-levels kf=2..nz-2
    auto q_im2 = q.slice(1, 0, nz - 3);
    auto q_im1 = q.slice(1, 1, nz - 2);
    auto q_i   = q.slice(1, 2, nz - 1);
    auto q_ip1 = q.slice(1, 3, nz);
    auto romI  = omega.slice(1, 2, nz - 1);
    torch::Tensor s_ua;   // sign(ua) with ua = -Omega (eta decreases upward); smooth for AD
    if (sign_delta > 0.0f) {
        s_ua = (-romI) / torch::sqrt(romI * romI + sign_delta * sign_delta);
    } else {
        s_ua = torch::sign(-romI).detach();
    }
    auto flux4 = (7.0f * (q_i + q_im1) - (q_ip1 + q_im2)) / 12.0f;
    auto fl3   = flux4 + s_ua * ((q_ip1 - q_im2) - 3.0f * (q_i - q_im1)) / 12.0f;
    auto vf_int = romI * fl3;                                               // {ny,nz-3,nx}
    // edge w-levels kf=1 and kf=nz-1 (2nd-order stretch-weighted)
    auto vf_k1 = omega.slice(1, 1, 2)
                 * (fzm.slice(1, 0, 1) * q.slice(1, 1, 2) + fzp.slice(1, 0, 1) * q.slice(1, 0, 1));
    auto vf_kt = omega.slice(1, nz - 1, nz)
                 * (fzm.slice(1, nz - 2, nz - 1) * q.slice(1, nz - 1, nz)
                    + fzp.slice(1, nz - 2, nz - 1) * q.slice(1, nz - 2, nz - 1));
    auto zerof = torch::zeros_like(vf_k1);
    auto vflux = torch::cat({zerof, vf_k1, vf_int, vf_kt, zerof}, 1);       // {ny,nz+1,nx}
    return (vflux.slice(1, 1, nz + 1) - vflux.slice(1, 0, nz))
           * rdnw_pos.slice(0, 0, nz).view({1, nz, 1});
}

// WRF advect_w vertical order-3 (module_advect_em.F advect_w vert_order==3; rdzu arg = WRF's
// NEGATIVE rdn). 0-based mapping (w-levels kf=0..nzm, mass levels m=0..nzm-1):
//   rom_mass[m] = 0.5*(Omega[m]+Omega[m+1])
//   vflux[m]: interior m=1..nzm-2 -> vel*flux3(w[m-1],w[m],w[m+1],w[m+2], ua=-vel);
//             m=0, nzm-1 -> 0.5*rom_mass*(w[m]+w[m+1])            [WRF's 0.25*(rom+rom)(w+w)]
//   tendency: kf=0 -> 0;  kf=1..nzm-1 -> +|rdn0[kf]|*(vflux[kf]-vflux[kf-1]);
//             LID kf=nzm -> -2*|rdn0[nzm-1]|*vflux[nzm-1]          [WRF's +2*rdzu(k-1)*vflux]
static torch::Tensor wrf_vert_adv3_w(const torch::Tensor& wf, const torch::Tensor& omega,
                                     const torch::Tensor& rdn_pos, float sign_delta) {
    const int64_t nzw = wf.size(1);
    const int64_t nzm = nzw - 1;
    auto romm = 0.5f * (omega.slice(1, 0, nzm) + omega.slice(1, 1, nzw));   // {ny,nzm,nx}
    auto q_im2 = wf.slice(1, 0, nzm - 2);
    auto q_im1 = wf.slice(1, 1, nzm - 1);
    auto q_i   = wf.slice(1, 2, nzm);
    auto q_ip1 = wf.slice(1, 3, nzw);
    auto velI  = romm.slice(1, 1, nzm - 1);
    torch::Tensor s_ua;
    if (sign_delta > 0.0f) {
        s_ua = (-velI) / torch::sqrt(velI * velI + sign_delta * sign_delta);
    } else {
        s_ua = torch::sign(-velI).detach();
    }
    auto flux4 = (7.0f * (q_i + q_im1) - (q_ip1 + q_im2)) / 12.0f;
    auto fl3   = flux4 + s_ua * ((q_ip1 - q_im2) - 3.0f * (q_i - q_im1)) / 12.0f;
    auto vf_int = velI * fl3;
    auto vf_bot = 0.5f * romm.slice(1, 0, 1) * (wf.slice(1, 0, 1) + wf.slice(1, 1, 2));
    auto vf_top = 0.5f * romm.slice(1, nzm - 1, nzm)
                  * (wf.slice(1, nzm - 1, nzm) + wf.slice(1, nzm, nzw));
    auto vflux = torch::cat({vf_bot, vf_int, vf_top}, 1);                   // {ny,nzm,nx}
    auto rdni = rdn_pos.slice(0, 1, nzm).view({1, nzm - 1, 1});             // |rdn0[1..nzm-1]|
    auto tend_int = rdni * (vflux.slice(1, 1, nzm) - vflux.slice(1, 0, nzm - 1));
    auto zbot = torch::zeros_like(vflux.slice(1, 0, 1));
    auto tlid = -2.0f * rdn_pos[nzm - 1] * vflux.slice(1, nzm - 1, nzm);
    return torch::cat({zbot, tend_int, tlid}, 1);                           // {ny,nzw,nx}
}

// ========================================================================
// HELPER FUNCTIONS FOR FUNCTIONAL TENSOR OPERATIONS
// These functions avoid in-place modifications to maintain autograd compatibility
// ========================================================================

namespace {

// Helper function to set a slice of a tensor functionally
// REMOVED 2025-12-28: setSliceValue() had O(n²) performance in loops.
// All callers should use tensor.index_put_() directly instead.

// PARITY FIX 2025-12-24: Autocast-aware epsilon selection for division safety.
// When autocast is enabled, operations may be cast to FP16 even if tensor.scalar_type()
// reports FP32 (storage dtype). This helper checks:
// 1. Check tensor's device type first (CUDA vs CPU)
// 2. Only check autocast for the matching device type
// 3. Fall back to tensor's actual dtype if autocast not enabled
// Note: BF16 has float32 exponent range so 1e-10f is safe; only FP16 needs 1e-4f.
//
// LibTorch version compatibility:
// - 1.10+: at::autocast::is_autocast_enabled(DeviceType), get_autocast_dtype(DeviceType)
// - <1.10: at::autocast::is_enabled(), get_autocast_gpu_dtype(), get_autocast_cpu_dtype()
#if TORCH_VERSION_MAJOR > 1 || (TORCH_VERSION_MAJOR == 1 && TORCH_VERSION_MINOR >= 10)
#define AUTOCAST_HAS_DEVICE_API 1
#define DEVICE_HAS_INDEX_API 1
#else
#define AUTOCAST_HAS_DEVICE_API 0
#define DEVICE_HAS_INDEX_API 0
#endif

// Helper for device.has_index() compatibility (added in 1.10)
// In older versions, index() returns -1 when no explicit index is set
inline bool device_has_explicit_index(const torch::Device& device) {
#if DEVICE_HAS_INDEX_API
    return device.has_index();
#else
    // Fallback: check if index is not -1 (the default "unset" value)
    return device.index() != -1;
#endif
}

inline float getAutocastAwareEps(const torch::Tensor& tensor, float fp16_eps = 1e-4f, float default_eps = 1e-10f) {
    // PARITY FIX 2025-12-24: Check tensor device first to avoid cross-device autocast mismatch.
    // Only check autocast for the device where the tensor resides.
    if (tensor.is_cuda()) {
#if AUTOCAST_HAS_DEVICE_API
        if (at::autocast::is_autocast_enabled(at::kCUDA)) {
            auto autocast_dtype = at::autocast::get_autocast_dtype(at::kCUDA);
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
            // BF16 has float32 exponent range, so default_eps is safe
        }
#else
        // Legacy API for LibTorch < 1.10
        if (at::autocast::is_enabled()) {
            auto autocast_dtype = at::autocast::get_autocast_gpu_dtype();
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
        }
#endif
    } else if (tensor.device().is_cpu()) {
#if AUTOCAST_HAS_DEVICE_API
        if (at::autocast::is_autocast_enabled(at::kCPU)) {
            auto autocast_dtype = at::autocast::get_autocast_dtype(at::kCPU);
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
            // BF16 on CPU also has float32 exponent range
        }
#else
        // Legacy API: CPU autocast not available in old versions, skip
#endif
    }
    // Fallback: check tensor's actual storage dtype
    if (tensor.scalar_type() == torch::kFloat16) {
        return fp16_eps;
    }
    return default_eps;
}

// Overload for when tensor is not available (use device type hint)
// FIX 2025-01-25: [[maybe_unused]] to suppress -Wunused-function (kept for future use)
[[maybe_unused]] inline float getAutocastAwareEps(at::DeviceType device_type, float fp16_eps = 1e-4f, float default_eps = 1e-10f) {
    if (device_type == at::kCUDA) {
#if AUTOCAST_HAS_DEVICE_API
        if (at::autocast::is_autocast_enabled(at::kCUDA)) {
            auto autocast_dtype = at::autocast::get_autocast_dtype(at::kCUDA);
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
        }
#else
        if (at::autocast::is_enabled()) {
            auto autocast_dtype = at::autocast::get_autocast_gpu_dtype();
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
        }
#endif
    } else if (device_type == at::kCPU) {
#if AUTOCAST_HAS_DEVICE_API
        if (at::autocast::is_autocast_enabled(at::kCPU)) {
            auto autocast_dtype = at::autocast::get_autocast_dtype(at::kCPU);
            if (autocast_dtype == torch::kFloat16) {
                return fp16_eps;
            }
        }
#endif
    }
    return default_eps;
}

// Helper function to functionally set a 1D slice in the last dimension
// FIX 2025-01-25: [[maybe_unused]] to suppress -Wunused-function (kept for future use)
[[maybe_unused]] torch::Tensor setSlice1D(const torch::Tensor& tensor, int index, const torch::Tensor& value) {
    // Split tensor into parts
    std::vector<torch::Tensor> parts;
    
    if (index > 0) {
        parts.push_back(tensor.slice(-1, 0, index));
    }
    parts.push_back(value.unsqueeze(-1));
    if (index < tensor.size(-1) - 1) {
        parts.push_back(tensor.slice(-1, index + 1, tensor.size(-1) - index - 1));
    }
    
    return torch::cat(parts, -1);
}

// Helper function to functionally set a 2D slice
torch::Tensor setSlice2D(const torch::Tensor& tensor, 
                         int dim,
                         int index, 
                         const torch::Tensor& value) {
    // Split tensor along specified dimension
    std::vector<torch::Tensor> parts;
    
    if (index > 0) {
        parts.push_back(tensor.slice(dim, 0, index));
    }
    
    // Add the new value with proper dimension
    if (dim == 0) {
        parts.push_back(value.unsqueeze(0));
    } else if (dim == 1) {
        parts.push_back(value.unsqueeze(1));
    } else {
        parts.push_back(value.unsqueeze(2));
    }
    
    if (index < tensor.size(dim) - 1) {
        parts.push_back(tensor.slice(dim, index + 1, tensor.size(dim) - index - 1));
    }
    
    return torch::cat(parts, dim);
}

// Helper function to combine interior and boundary values functionally
torch::Tensor combineInteriorBoundary(const torch::Tensor& interior,
                                      const torch::Tensor& boundary,
                                      int start_idx,
                                      int end_idx,
                                      int dim) {
    // Create result tensor
    torch::Tensor result = boundary.clone();
    
    // Use narrow and cat to set interior values
    // CRITICAL FIX: slice(dim, start, end) takes end index, not length!
    if (dim == 0) {
        std::vector<torch::Tensor> parts;
        if (start_idx > 0) {
            parts.push_back(result.slice(0, 0, start_idx));
        }
        parts.push_back(interior);
        if (end_idx < result.size(0)) {
            parts.push_back(result.slice(0, end_idx, result.size(0)));  // Fixed: use end index
        }
        result = torch::cat(parts, 0);
    } else if (dim == 1) {
        std::vector<torch::Tensor> parts;
        if (start_idx > 0) {
            parts.push_back(result.slice(1, 0, start_idx));
        }
        parts.push_back(interior);
        if (end_idx < result.size(1)) {
            parts.push_back(result.slice(1, end_idx, result.size(1)));  // Fixed: use end index
        }
        result = torch::cat(parts, 1);
    } else if (dim == 2) {
        std::vector<torch::Tensor> parts;
        if (start_idx > 0) {
            parts.push_back(result.slice(2, 0, start_idx));
        }
        parts.push_back(interior);
        if (end_idx < result.size(2)) {
            parts.push_back(result.slice(2, end_idx, result.size(2)));  // Fixed: use end index
        }
        result = torch::cat(parts, 2);
    }
    
    return result;
}

// Helper function to fill halo regions with periodic values for single-tile case
// This is critical for 5th-order advection which needs halo values
// CRITICAL: Uses gradient-preserving operations for automatic differentiation
// FIX 2025-01-25: [[maybe_unused]] to suppress -Wunused-function (kept for future use)
[[maybe_unused]] torch::Tensor applyPeriodicHaloFill(const torch::Tensor& field,
                                    int halo_width,
                                    bool periodic_x,
                                    bool periodic_y,
                                    const std::string& stagger_type = "mass") {
    // CRITICAL FIX: SDIRK3 should NOT handle halo processing
    // WRF already manages all halo exchanges and boundary conditions
    // SDIRK3 should only operate on interior points (its:ite, jts:jte, kts:kte)
    // Return field unchanged to prevent improper halo modification
    return field;
    
    // CRITICAL FIX v4: Use proper gradient-preserving operations
    // slice() + copy_() maintains autograd graph for Newton-Krylov JVP
    
    int ny = field.size(0);
    [[maybe_unused]] int nz = field.size(1);
    int nx = field.size(2);
    
    // Start with a copy of the field to preserve interior values
    torch::Tensor result = field.clone();
    
    // CRITICAL: Initialize halos to zero if they contain NaN or Inf
    // This prevents propagation of uninitialized values through advection
    // PERFORMANCE: Only validate at debug_level >= 1 to avoid .item<bool>() GPU syncs in production
    bool needs_halo_init = false;

    if (wrf::sdirk3::g_sdirk3_config.debug_level >= 1) {
        torch::NoGradGuard no_grad;  // Halo validation and initialization don't need gradients

        // Check if halos are initialized before filling
        if (nx > 2 * halo_width) {
            auto left_halo_check = result.slice(2, 0, halo_width);
            auto right_halo_check = result.slice(2, nx - halo_width, nx);

            // PERF FIX 2025-12-27: Pre-copy halos to CPU once, then check for NaN/Inf
            // OPT Pass32: Batch 4 .item<bool>() into single D2H with torch::stack()
            auto left_cpu = left_halo_check.detach().to(torch::kCPU);
            auto right_cpu = right_halo_check.detach().to(torch::kCPU);
            auto checks_cpu = torch::stack({
                torch::isnan(left_cpu).any(),
                torch::isinf(left_cpu).any(),
                torch::isnan(right_cpu).any(),
                torch::isinf(right_cpu).any()
            });
            bool left_contains_nan = checks_cpu[0].item<bool>();
            bool left_contains_inf = checks_cpu[1].item<bool>();
            bool right_contains_nan = checks_cpu[2].item<bool>();
            bool right_contains_inf = checks_cpu[3].item<bool>();

            if (left_contains_nan || left_contains_inf || right_contains_nan || right_contains_inf) {
                needs_halo_init = true;

                if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
                    std::cerr << "\n=== HALO INITIALIZATION NEEDED (" << stagger_type << ") ===" << std::endl;
                    std::cerr << "  Left halo has NaN: " << left_contains_nan << ", Inf: " << left_contains_inf << std::endl;
                    std::cerr << "  Right halo has NaN: " << right_contains_nan << ", Inf: " << right_contains_inf << std::endl;
                }

                // Initialize X halos to zero
                left_halo_check.zero_();
                right_halo_check.zero_();
            }
        }

        if (ny > 2 * halo_width) {
            auto bottom_halo_check = result.slice(0, 0, halo_width);
            auto top_halo_check = result.slice(0, ny - halo_width, ny);

            // PERF FIX 2025-12-27: Pre-copy halos to CPU once, then check for NaN/Inf
            // OPT Pass32: Batch 4 .item<bool>() into single D2H with torch::stack()
            auto bottom_cpu = bottom_halo_check.detach().to(torch::kCPU);
            auto top_cpu = top_halo_check.detach().to(torch::kCPU);
            auto checks_y_cpu = torch::stack({
                torch::isnan(bottom_cpu).any(),
                torch::isinf(bottom_cpu).any(),
                torch::isnan(top_cpu).any(),
                torch::isinf(top_cpu).any()
            });
            bool bottom_contains_nan = checks_y_cpu[0].item<bool>();
            bool bottom_contains_inf = checks_y_cpu[1].item<bool>();
            bool top_contains_nan = checks_y_cpu[2].item<bool>();
            bool top_contains_inf = checks_y_cpu[3].item<bool>();

            if (bottom_contains_nan || bottom_contains_inf || top_contains_nan || top_contains_inf) {
                needs_halo_init = true;

                if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
                    std::cerr << "  Bottom halo has NaN: " << bottom_contains_nan << ", Inf: " << bottom_contains_inf << std::endl;
                    std::cerr << "  Top halo has NaN: " << top_contains_nan << ", Inf: " << top_contains_inf << std::endl;
                }

                // Initialize Y halos to zero
                bottom_halo_check.zero_();
                top_halo_check.zero_();
            }
        }

        if (needs_halo_init && wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
            std::cerr << "  Initialized halos to zero to prevent NaN/Inf propagation" << std::endl;
        }
    }
    
    // Debug: Check values before periodic fill
    // OPT Pass32: Batch 4 min/max .item<float>() into single D2H
    if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2 && (periodic_x || periodic_y)) {
        auto left_halo_before = result.slice(2, 0, std::min(halo_width, nx));
        auto right_halo_before = result.slice(2, std::max(0, nx - halo_width), nx);

        torch::NoGradGuard no_grad;
        auto left_before_cpu = left_halo_before.detach().to(torch::kCPU);
        auto right_before_cpu = right_halo_before.detach().to(torch::kCPU);
        auto stats_before = torch::stack({
            left_before_cpu.min(), left_before_cpu.max(),
            right_before_cpu.min(), right_before_cpu.max()
        });
        std::cerr << "\n=== HALO VALUES BEFORE PERIODIC FILL (" << stagger_type << ") ===" << std::endl;
        std::cerr << "  Left halo min/max: "
                  << stats_before[0].item<float>() << " / "
                  << stats_before[1].item<float>() << std::endl;
        std::cerr << "  Right halo min/max: "
                  << stats_before[2].item<float>() << " / "
                  << stats_before[3].item<float>() << std::endl;
    }
    
    // Fill X-direction halos if periodic_x is enabled
    if (periodic_x && nx > 2 * halo_width) {
        // Interior region bounds (excluding halos)
        int i_start = halo_width;
        int i_end = nx - halo_width;
        
        // WRF-compatible periodic halo filling:
        // Left halo [0:halo_width] <- right interior [i_end-halo_width:i_end]
        // Right halo [i_end:nx] <- left interior [i_start:i_start+halo_width]
        
        // Use slice() and copy_() for gradient preservation
        // copy_() is the correct method for in-place tensor copy in PyTorch C++
        
        // Fill left halo with right interior (periodic wrap)
        auto left_halo = result.slice(2, 0, halo_width);
        auto right_interior = field.slice(2, i_end - halo_width, i_end);
        left_halo.copy_(right_interior);
        
        // Fill right halo with left interior (periodic wrap)
        auto right_halo = result.slice(2, i_end, nx);
        auto left_interior = field.slice(2, i_start, i_start + halo_width);
        right_halo.copy_(left_interior);
        
        // Debug: Check values after X-periodic fill
        // OPT Pass32: Batch 4 min/max .item<float>() into single D2H
        if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
            // GRADIENT FIX: Cache halo min/max inside guard
            float left_min, left_max, right_min, right_max;
            bool req_grad;
            {
                torch::NoGradGuard no_grad;
                auto left_cpu = left_halo.detach().to(torch::kCPU);
                auto right_cpu = right_halo.detach().to(torch::kCPU);
                auto stats_cpu = torch::stack({
                    left_cpu.min(), left_cpu.max(),
                    right_cpu.min(), right_cpu.max()
                });
                left_min = stats_cpu[0].item<float>();
                left_max = stats_cpu[1].item<float>();
                right_min = stats_cpu[2].item<float>();
                right_max = stats_cpu[3].item<float>();
                req_grad = result.requires_grad();
            }

            std::cerr << "After X-periodic fill:" << std::endl;
            std::cerr << "  Left halo [0:" << halo_width << "] min/max: "
                      << left_min << " / " << left_max << std::endl;
            std::cerr << "  Right halo [" << i_end << ":" << nx << "] min/max: "
                      << right_min << " / " << right_max << std::endl;
            std::cerr << "  requires_grad: " << req_grad << std::endl;
        }
    }

    // Fill Y-direction halos if periodic_y is enabled
    if (periodic_y && ny > 2 * halo_width) {
        // Interior region bounds (excluding halos)
        int j_start = halo_width;
        int j_end = ny - halo_width;
        
        // WRF-compatible periodic halo filling in Y:
        // Bottom halo [0:halo_width] <- top interior [j_end-halo_width:j_end]
        // Top halo [j_end:ny] <- bottom interior [j_start:j_start+halo_width]
        
        // Fill bottom halo with top interior (periodic wrap)
        auto bottom_halo = result.slice(0, 0, halo_width);
        auto top_interior = result.slice(0, j_end - halo_width, j_end);
        bottom_halo.copy_(top_interior);
        
        // Fill top halo with bottom interior (periodic wrap)
        auto top_halo = result.slice(0, j_end, ny);
        auto bottom_interior = result.slice(0, j_start, j_start + halo_width);
        top_halo.copy_(bottom_interior);
        
        // Debug: Check values after Y-periodic fill
        // OPT Pass32: Batch 4 min/max .item<float>() into single D2H
        if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
            // GRADIENT FIX: Cache halo min/max inside guard
            float bottom_min, bottom_max, top_min, top_max;
            {
                torch::NoGradGuard no_grad;
                auto bottom_cpu = bottom_halo.detach().to(torch::kCPU);
                auto top_cpu = top_halo.detach().to(torch::kCPU);
                auto stats_y_cpu = torch::stack({
                    bottom_cpu.min(), bottom_cpu.max(),
                    top_cpu.min(), top_cpu.max()
                });
                bottom_min = stats_y_cpu[0].item<float>();
                bottom_max = stats_y_cpu[1].item<float>();
                top_min = stats_y_cpu[2].item<float>();
                top_max = stats_y_cpu[3].item<float>();
            }

            std::cerr << "After Y-periodic fill:" << std::endl;
            std::cerr << "  Bottom halo [0:" << halo_width << "] min/max: "
                      << bottom_min << " / " << bottom_max << std::endl;
            std::cerr << "  Top halo [" << j_end << ":" << ny << "] min/max: "
                      << top_min << " / " << top_max << std::endl;
        }
    }

    // Final validation
    // OPT Pass32: Batch 2 min/max .item<float>() into single D2H
    if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
        // GRADIENT FIX: Cache result min/max inside guard
        float result_min, result_max;
        {
            torch::NoGradGuard no_grad;
            auto result_cpu = result.detach().to(torch::kCPU);
            auto stats_final = torch::stack({result_cpu.min(), result_cpu.max()});
            result_min = stats_final[0].item<float>();
            result_max = stats_final[1].item<float>();
        }

        std::cerr << "Final result min/max: " << result_min << " / " << result_max << std::endl;

        if (std::isnan(result_min) || std::isnan(result_max)) {
            std::cerr << "ERROR: Result contains NaN after periodic fill!" << std::endl;
        }
        if (std::isinf(result_min) || std::isinf(result_max)) {
            std::cerr << "ERROR: Result contains Inf after periodic fill!" << std::endl;
        }
    }
    
    return result;
}

} // anonymous namespace

// =========================================================================
// GRAPH SIMPLIFICATION 2025-12-14: Utility helper implementations
// =========================================================================

std::pair<torch::Tensor, torch::Tensor> TileSDIRK3UnifiedSolver::alignAndSliceFnmFnp(
    int64_t k_start, int64_t k_end, const torch::Device& dev, torch::ScalarType dtype) const {

    // Validate range
    int64_t slice_len = k_end - k_start;
    if (slice_len <= 0) {
        auto opts = torch::TensorOptions().device(dev).dtype(dtype);
        return {torch::empty({0}, opts), torch::empty({0}, opts)};
    }

    auto opts = torch::TensorOptions().device(dev).dtype(dtype);

    // Handle undefined or empty tensors with fallback
    if (!fnm_.defined() || fnm_.numel() == 0 || !fnp_.defined() || fnp_.numel() == 0) {
        return {torch::full({slice_len}, 0.5f, opts), torch::full({slice_len}, 0.5f, opts)};
    }

    // Align to target device/dtype if needed
    torch::Tensor fnm_aligned = (fnm_.device() != dev || fnm_.scalar_type() != dtype)
        ? fnm_.to(dev, dtype, /*non_blocking=*/true)
        : fnm_;
    torch::Tensor fnp_aligned = (fnp_.device() != dev || fnp_.scalar_type() != dtype)
        ? fnp_.to(dev, dtype, /*non_blocking=*/true)
        : fnp_;

    int64_t fnm_size = fnm_aligned.size(0);
    int64_t fnp_size = fnp_aligned.size(0);

    // Slice to [k_start, k_end) range, clamped to available data
    int64_t fnm_start = std::min(k_start, fnm_size);
    int64_t fnm_end = std::min(k_end, fnm_size);
    int64_t fnp_start = std::min(k_start, fnp_size);
    int64_t fnp_end = std::min(k_end, fnp_size);

    torch::Tensor fnm_result, fnp_result;

    // Process fnm: slice available range, then pad to slice_len if needed
    if (fnm_end > fnm_start) {
        // Slice and ensure on target device/dtype
        fnm_result = fnm_aligned.slice(0, fnm_start, fnm_end);
        if (fnm_result.device() != dev || fnm_result.scalar_type() != dtype) {
            fnm_result = fnm_result.to(dev, dtype, /*non_blocking=*/true);
        }
        int64_t fnm_got = fnm_result.size(0);
        if (fnm_got < slice_len) {
            // Pad with last value using tensor slice+expand (avoids GPU→CPU sync)
            auto pad = fnm_result.slice(0, fnm_got - 1, fnm_got).expand({slice_len - fnm_got});
            fnm_result = torch::cat({fnm_result, pad}, 0);
        }
    } else {
        fnm_result = torch::full({slice_len}, 0.5f, opts);
    }

    // Process fnp: slice available range, then pad to slice_len if needed
    if (fnp_end > fnp_start) {
        // Slice and ensure on target device/dtype
        fnp_result = fnp_aligned.slice(0, fnp_start, fnp_end);
        if (fnp_result.device() != dev || fnp_result.scalar_type() != dtype) {
            fnp_result = fnp_result.to(dev, dtype, /*non_blocking=*/true);
        }
        int64_t fnp_got = fnp_result.size(0);
        if (fnp_got < slice_len) {
            // Pad with last value using tensor slice+expand (avoids GPU→CPU sync)
            auto pad = fnp_result.slice(0, fnp_got - 1, fnp_got).expand({slice_len - fnp_got});
            fnp_result = torch::cat({fnp_result, pad}, 0);
        }
    } else {
        fnp_result = torch::full({slice_len}, 0.5f, opts);
    }

    return {fnm_result, fnp_result};
}

torch::Tensor TileSDIRK3UnifiedSolver::expand1dTo3d(
    const torch::Tensor& coeff_1d, int64_t ny, int64_t nz, int64_t nx) const {

    if (!coeff_1d.defined() || coeff_1d.numel() == 0) {
        return torch::zeros({ny, nz, nx}, coeff_1d.options());
    }

    // Slice to nz if larger, otherwise use as-is
    int64_t coeff_size = coeff_1d.size(0);
    torch::Tensor coeff_slice = (coeff_size > nz) ? coeff_1d.slice(0, 0, nz) : coeff_1d;

    // If coeff is smaller than nz, pad with last value
    if (coeff_size < nz) {
        auto last_val = coeff_1d[-1];
        auto pad = last_val.expand({nz - coeff_size});
        coeff_slice = torch::cat({coeff_1d, pad}, 0);
    }

    // Reshape to [1, nz, 1] and broadcast to [ny, nz, nx]
    return coeff_slice.view({1, nz, 1}).expand({ny, nz, nx}).contiguous();
}

std::pair<torch::Tensor, torch::Tensor> TileSDIRK3UnifiedSolver::alignAndSliceFnmFnp3d(
    int64_t k_start, int64_t k_end, int64_t ny, int64_t nx,
    const torch::Device& dev, torch::ScalarType dtype) const {

    // Get 1D aligned slices first
    auto [fnm_1d, fnp_1d] = alignAndSliceFnmFnp(k_start, k_end, dev, dtype);

    int64_t nk = fnm_1d.size(0);
    if (nk == 0) {
        auto opts = torch::TensorOptions().device(dev).dtype(dtype);
        return {torch::empty({ny, 0, nx}, opts), torch::empty({ny, 0, nx}, opts)};
    }

    // Expand to 3D: [nk] -> [1, nk, 1] -> [ny, nk, nx]
    auto fnm_3d = fnm_1d.view({1, nk, 1}).expand({ny, nk, nx});
    auto fnp_3d = fnp_1d.view({1, nk, 1}).expand({ny, nk, nx});

    return {fnm_3d, fnp_3d};
}

