// IEVA-based vertical stability metric calculation (Shchepetkin 2015)
// Full Fortran parity with module_ieva_em.F WW_SPLIT subroutine
// PARITY FIX 2025-12-10: Complete rewrite to match Fortran IEVA logic
//
// Fortran reference (module_ieva_em.F:230-250):
//   cx = 0.25*rdx*(u(i+1,k,j) + u(i,k,j) + u(i+1,k-1,j) + u(i,k-1,j))
//   cy = 0.25*rdy*(v(i,k,j+1) + v(i,k,j) + v(i,k-1,j+1) + v(i,k-1,j))
//   cw_max = max(alpha_max - dt*Ceps*sqrt(cx**2 + cy**2), 0.0)
//   cr = ww(i,k,j) * dt * rdnw(k) / (c1f(k)*mut(i,j) + c2f(k))
//
// Key differences from previous implementation:
// 1. Uses ww (contravariant omega) instead of w (physical vertical velocity)
// 2. Includes mut and c1f/c2f scaling for proper eta-coordinate Courant
// 3. Uses rdnw (eta spacing) instead of physical dz
// 4. Computes cw_max adjusted by horizontal divergence
// 5. Maintains autograd compatibility for gradients to mut and horizontal flow
torch::Tensor TileSDIRK3UnifiedSolver::computeVerticalStabilityMetric(
    const torch::Tensor& ww,
    const torch::Tensor& u,
    const torch::Tensor& v,
    const torch::Tensor& mut,
    const torch::Tensor& c1f,
    const torch::Tensor& c2f,
    const torch::Tensor& rdnw,
    float rdx, float rdy,
    float dt) const {

    // ===================================================================
    // IEVA parameters from Fortran (module_ieva_em.F:8-9, 94-97)
    // ===================================================================
    constexpr float alpha_max = 1.1f;   // Maximum allowed vertical Courant
    constexpr float alpha_min = 0.8f;   // Minimum for transition region
    constexpr float Ceps = 0.9f;        // Horizontal divergence coupling coefficient

    // Get dimensions - ww is at w-staggered points [ny, nz_w, nx]
    auto ny = ww.size(0);
    auto nz_w = ww.size(1);
    auto nx = ww.size(2);
    int nz = static_cast<int>(nz_w) - 1;  // Mass levels

    // Validate inputs
    if (!mut.defined() || mut.numel() == 0) {
        if (wrf::sdirk3::g_sdirk3_config.debug_level >= 1) {
            std::cerr << "VerticalCFL WARNING: mut not provided, returning zero CFL" << std::endl;
        }
        return torch::zeros({ny, nx}, ww.options());
    }
    if (!c1f.defined() || !c2f.defined() || !rdnw.defined()) {
        if (wrf::sdirk3::g_sdirk3_config.debug_level >= 1) {
            std::cerr << "VerticalCFL WARNING: c1f/c2f/rdnw not provided, returning zero CFL" << std::endl;
        }
        return torch::zeros({ny, nx}, ww.options());
    }

    // ===================================================================
    // Compute horizontal Courant numbers for cw_max adjustment
    // Fortran: cx = 0.25*rdx*(u(i+1,k,j) + u(i,k,j) + u(i+1,k-1,j) + u(i,k-1,j))
    // This requires averaging u at 4 corners around mass point (i,k,j)
    // ===================================================================

    // u is [ny, nz, nx_u] where nx_u = nx + 1 (u-staggered)
    // v is [ny_v, nz, nx] where ny_v = ny + 1 (v-staggered)
    // We compute mean flow Courant at mass points interior (k=1 to nz-1)

    torch::Tensor cx_3d, cy_3d;
    bool have_horizontal = false;

    // PARITY FIX 2025-12-10: Strict shape guard for staggered u/v
    // u.slice(2, 1, nx+1) requires u.size(2) >= nx+1 (u-staggered has nx+1 points)
    // v.slice(0, 1, ny+1) requires v.size(0) >= ny+1 (v-staggered has ny+1 points)
    // Previous guard (>= nx, >= ny) was too lax and could cause out-of-bounds access
    if (u.defined() && u.numel() > 0 && v.defined() && v.numel() > 0 &&
        u.size(0) == ny && u.size(1) == nz && u.size(2) >= nx + 1 &&
        v.size(0) >= ny + 1 && v.size(1) == nz && v.size(2) == nx) {

        // For interior w-levels k=1..nz-1, average u at (k-1, k) mass levels
        // Fortran loops k=kts+1 to ktf-1, which maps to C++ k=1 to nz-1

        // u averaging: u(i+1,k,j) + u(i,k,j) + u(i+1,k-1,j) + u(i,k-1,j)
        // For simplicity, use 2-level average at each w-level
        auto u_i = u.slice(2, 0, nx);           // u at i
        auto u_ip1 = u.slice(2, 1, nx + 1);     // u at i+1
        auto u_avg_i = 0.5f * (u_i + u_ip1);    // [ny, nz, nx] average in i

        // Average in k: (u_avg[k] + u_avg[k-1]) for w-levels
        auto u_k = u_avg_i.slice(1, 1, nz);     // k levels [ny, nz-1, nx]
        auto u_km1 = u_avg_i.slice(1, 0, nz - 1); // k-1 levels [ny, nz-1, nx]
        auto u_avg_kw = 0.5f * (u_k + u_km1);   // [ny, nz-1, nx] at interior w-levels

        cx_3d = rdx * u_avg_kw;  // Horizontal Courant in x

        // v averaging: v(i,k,j+1) + v(i,k,j) + v(i,k-1,j+1) + v(i,k-1,j)
        auto v_j = v.slice(0, 0, ny);           // v at j
        auto v_jp1 = v.slice(0, 1, ny + 1);     // v at j+1
        auto v_avg_j = 0.5f * (v_j + v_jp1);    // [ny, nz, nx] average in j

        auto v_k = v_avg_j.slice(1, 1, nz);
        auto v_km1 = v_avg_j.slice(1, 0, nz - 1);
        auto v_avg_kw = 0.5f * (v_k + v_km1);   // [ny, nz-1, nx]

        cy_3d = rdy * v_avg_kw;  // Horizontal Courant in y

        have_horizontal = true;
    }

    // ===================================================================
    // Compute adjusted cw_max based on horizontal flow
    // Fortran: cw_max = max(alpha_max - dt*Ceps*sqrt(cx**2 + cy**2), 0.0)
    // ===================================================================

    torch::Tensor cw_max_3d;  // [ny, nz-1, nx] at interior w-levels
    if (have_horizontal) {
        auto c_horiz = torch::sqrt(cx_3d.square() + cy_3d.square());
        cw_max_3d = (alpha_max - dt * Ceps * c_horiz).clamp_min(0.0f);
    } else {
        // No horizontal info, use constant alpha_max
        cw_max_3d = torch::full({ny, nz - 1, nx}, alpha_max, ww.options());
    }

    // ===================================================================
    // Compute vertical Courant number cr
    // Fortran: cr = ww(i,k,j) * dt * rdnw(k) / (c1f(k)*mut(i,j) + c2f(k))
    // Fortran loop: DO k = 2, ktf-1 (1-based), which is C++ k = 1 to nz-1 (0-based)
    // ===================================================================

    // PARITY FIX 2025-12-13: Device alignment for vertical coordinate coefficients and mut
    // c1f/c2f/rdnw are CPU tensors from setVerticalCoordinateCoefficients (from_blob)
    // mut may also be CPU, but ww can be on GPU - align to avoid device mismatch
    auto target_device = ww.device();
    auto target_dtype = ww.scalar_type();

    torch::Tensor c1f_dev = (c1f.device() != target_device)
        ? c1f.to(target_device, target_dtype, /*non_blocking=*/true)
        : c1f;
    torch::Tensor c2f_dev = (c2f.device() != target_device)
        ? c2f.to(target_device, target_dtype, /*non_blocking=*/true)
        : c2f;
    torch::Tensor rdnw_dev = (rdnw.device() != target_device)
        ? rdnw.to(target_device, target_dtype, /*non_blocking=*/true)
        : rdnw;
    torch::Tensor mut_dev = (mut.device() != target_device)
        ? mut.to(target_device, target_dtype, /*non_blocking=*/true)
        : mut;

    // Extract interior w-levels of ww (k=1 to nz-1 in 0-based)
    auto ww_interior = ww.slice(1, 1, nz);  // [ny, nz-1, nx]

    // PARITY FIX 2025-12-10: rdnw slice must match w-level indexing
    // Fortran uses rdnw(k) where k is the w-level index (2 to ktf-1 in 1-based)
    // C++ interior w-levels are k=1 to nz-1, so rdnw indices are also 1 to nz-1
    // Previous: rdnw.slice(0, 0, nz-1) was using rdnw[0..nz-2] (off by one!)
    // Corrected: rdnw.slice(0, 1, nz) uses rdnw[1..nz-1] matching Fortran rdnw(2..ktf-1)
    auto rdnw_interior = rdnw_dev.slice(0, 1, nz);  // [nz-1]

    // c1f, c2f are [nz_w] at w-levels, extract interior (already correct: k=1 to nz-1)
    auto c1f_interior = c1f_dev.slice(0, 1, nz);  // [nz-1]
    auto c2f_interior = c2f_dev.slice(0, 1, nz);  // [nz-1]

    // mut is [ny, nx], broadcast for 3D computation
    // Compute denominator: c1f(k)*mut(i,j) + c2f(k)
    // Shape broadcasting: c1f[nz-1] * mut[ny,nx] + c2f[nz-1]
    auto mut_3d = mut_dev.unsqueeze(1);  // [ny, 1, nx]
    auto c1f_3d = c1f_interior.view({1, -1, 1});  // [1, nz-1, 1]
    auto c2f_3d = c2f_interior.view({1, -1, 1});  // [1, nz-1, 1]
    auto rdnw_3d = rdnw_interior.view({1, -1, 1}); // [1, nz-1, 1]

    // Denominator: c1f*mut + c2f (avoid divide by zero)
    // PARITY FIX 2025-12-24: Use autocast-aware epsilon to prevent float16 underflow.
    // getAutocastAwareEps checks both storage dtype AND autocast state.
    auto denom_raw = c1f_3d * mut_3d + c2f_3d;
    const float denom_eps = getAutocastAwareEps(denom_raw);
    auto denom = denom_raw.clamp_min(denom_eps);  // [ny, nz-1, nx]

    // Vertical Courant: cr = ww * dt * rdnw / (c1f*mut + c2f)
    auto cr_3d = ww_interior * dt * rdnw_3d / denom;  // [ny, nz-1, nx]
    auto cw_3d = torch::abs(cr_3d);  // |cr|

    // ===================================================================
    // PARITY FIX 2025-12-10: Implement full IEVA wfrac limiter logic
    // Fortran (module_ieva_em.F:238-251):
    //   cw_max2 = cw_max**2
    //   cw_min  = cw_max * cmnx_ratio   (cmnx_ratio = alpha_min/alpha_max)
    //   cw      = abs(cr)
    //   if (cw < cw_min) then
    //       cff = cw_max2
    //   elseif (cw < cutoff*cw_min) then
    //       cff = cw_max2 + r4cmx*(cw-cw_min)**2
    //   else
    //       cff = cw_max*cw
    //   endif
    //   wfrac = cw_max2 / cff   (clamped to [0,1])
    //   wwE = ww * wfrac        (explicit part)
    //   wwI = ww * (1 - wfrac)  (implicit part)
    //
    // The effective explicit Courant is |cr| * wfrac, which is reduced
    // when cw_max is small (due to high horizontal flow).
    // ===================================================================

    // IEVA limiter parameters (module_ieva_em.F:94-96)
    constexpr float cmnx_ratio = alpha_min / alpha_max;  // 0.8/1.1 ≈ 0.727
    constexpr float cutoff = 2.0f - cmnx_ratio;          // ≈ 1.273
    constexpr float r4cmx = 1.0f / (4.0f - 4.0f * cmnx_ratio);  // ≈ 0.917

    // Compute wfrac using IEVA limiter (vectorized)
    auto cw_max2 = cw_max_3d.square();                    // cw_max^2
    auto cw_min = cw_max_3d * cmnx_ratio;                 // cw_max * (alpha_min/alpha_max)

    // Three-region limiter:
    // Region 1: cw < cw_min          → cff = cw_max2 (full explicit)
    // Region 2: cw_min ≤ cw < cutoff*cw_min → cff = cw_max2 + r4cmx*(cw-cw_min)^2 (transition)
    // Region 3: cw ≥ cutoff*cw_min   → cff = cw_max * cw (partial implicit)

    auto cutoff_cw_min = cutoff * cw_min;

    // Compute cff for each region using where() for vectorized branching
    auto cff_region1 = cw_max2;
    auto cff_region2 = cw_max2 + r4cmx * (cw_3d - cw_min).square();
    auto cff_region3 = cw_max_3d * cw_3d;

    // Select cff based on region
    auto in_region1 = cw_3d < cw_min;
    auto in_region2 = (cw_3d >= cw_min) & (cw_3d < cutoff_cw_min);
    // Region 3 is the else case

    auto cff = torch::where(in_region1, cff_region1,
               torch::where(in_region2, cff_region2, cff_region3));

    // wfrac = cw_max2 / cff, clamped to [0, 1]
    // When cw_max = 0 (very fast horizontal flow), wfrac = 0 (fully implicit)
    // PARITY FIX 2025-12-24: Use dtype-aware epsilon (FP16 only, BF16 is safe).
    const float cff_eps = getAutocastAwareEps(cff);
    auto wfrac = (cw_max2 / cff.clamp_min(cff_eps)).clamp(0.0f, 1.0f);

    // Handle cw_max = 0 case: wfrac should be 0 (fully implicit)
    wfrac = torch::where(cw_max_3d > 0.0f, wfrac, torch::zeros_like(wfrac));

    // ===================================================================
    // Effective explicit Courant: |cr| * wfrac
    // This is what actually determines explicit stability after IEVA splitting
    // When horizontal flow is high (small cw_max), wfrac is reduced,
    // lowering the effective explicit Courant even if |cr| is large.
    // ===================================================================

    auto effective_cfl_3d = cw_3d * wfrac;  // [ny, nz-1, nx]

    // Take maximum over vertical dimension (dim=1): [ny, nx]
    auto vertical_cfl = std::get<0>(effective_cfl_3d.max(1));

    if (wrf::sdirk3::g_sdirk3_config.debug_level >= 2) {
        torch::NoGradGuard no_grad;
        // PERF FIX 2025-12-28: Pre-copy tensors to CPU with _cpu suffix for consistency
        auto cw_3d_cpu = cw_3d.detach().to(torch::kCPU);
        auto vertical_cfl_cpu = vertical_cfl.detach().to(torch::kCPU);
        auto wfrac_cpu = wfrac.detach().to(torch::kCPU);
        auto cw_max_3d_cpu = cw_max_3d.detach().to(torch::kCPU);
        // PERF FIX 2025-12-28: Pre-compute reductions with _cpu suffix
        auto max_raw_cfl_cpu = cw_3d_cpu.max();
        auto max_eff_cfl_cpu = vertical_cfl_cpu.max();
        auto min_wfrac_cpu = wfrac_cpu.min();
        auto cw_max_min_cpu = cw_max_3d_cpu.min();
        auto max_raw_cfl = max_raw_cfl_cpu.item<float>();
        auto max_eff_cfl = max_eff_cfl_cpu.item<float>();
        auto min_wfrac = min_wfrac_cpu.item<float>();
        auto cw_max_min = cw_max_min_cpu.item<float>();
        std::cerr << "VerticalCFL (IEVA parity): max|cr|=" << max_raw_cfl
                  << ", max_effective=" << max_eff_cfl
                  << ", min(wfrac)=" << min_wfrac
                  << ", min(cw_max)=" << cw_max_min << std::endl;
    }

    return vertical_cfl;
}

// PERF FIX 2025-12-28: Direct float overload - no GPU sync, use when caller pre-copies tensor
std::tuple<float, int> TileSDIRK3UnifiedSolver::getAdaptiveNewtonParameters(float cfl_value) const {
    // Default parameters from namelist
    float base_tolerance = 1.0e-4f;
    int base_max_iter = 10;

    // Adaptive strategy inspired by IEVA:
    // - High CFL (>0.8): Tighter tolerance, more iterations for stability
    // - Medium CFL (0.3-0.8): Standard parameters
    // - Low CFL (<0.3): Relaxed tolerance, fewer iterations for efficiency
    float tolerance;
    int max_iter;

    if (cfl_value > 0.8f) {
        // High CFL - needs careful treatment
        tolerance = base_tolerance * 0.1f;  // Tighter tolerance
        max_iter = base_max_iter + 5;       // More iterations allowed
    } else if (cfl_value > 0.3f) {
        // Medium CFL - standard treatment
        tolerance = base_tolerance;
        max_iter = base_max_iter;
    } else {
        // Low CFL - can relax convergence criteria
        tolerance = base_tolerance * 10.0f;  // Relaxed tolerance
        max_iter = std::max(5, base_max_iter - 3);  // Fewer iterations
    }

    return std::make_tuple(tolerance, max_iter);
}

// Get adaptive Newton solver parameters based on vertical stability (tensor version)
std::tuple<float, int> TileSDIRK3UnifiedSolver::getAdaptiveNewtonParameters(
    const torch::Tensor& vertical_cfl, int j, int i) const {

    // Extract CFL value from tensor (requires GPU sync)
    float cfl_value;
    {
        torch::NoGradGuard no_grad;  // Disable gradient tracking for control flow
        // PERF FIX 2025-12-28: Pre-copy to CPU with _cpu suffix for consistency
        torch::Tensor cfl = vertical_cfl.index({j, i});
        auto cfl_cpu = cfl.detach().to(torch::kCPU);
        cfl_value = cfl_cpu.item<float>();
    }

    // Delegate to float overload
    return getAdaptiveNewtonParameters(cfl_value);
}

