                auto th_base_max_cpu = th_base_cpu.max();
                auto t_full_min_cpu = t_full_cpu.min();
                auto t_full_max_cpu = t_full_cpu.max();
                bool t_has_nan = t_has_nan_cpu.item<bool>();
                bool t_has_inf = t_has_inf_cpu.item<bool>();
                bool t_full_has_nan = t_full_has_nan_cpu.item<bool>();
                bool t_full_has_inf = t_full_has_inf_cpu.item<bool>();
