                auto t_at_w_has_inf_cpu = t_at_w_cpu.isinf().any();
                auto t_at_w_min_cpu = t_at_w_cpu.min();
                auto t_at_w_max_cpu = t_at_w_cpu.max();
                auto th_base_at_w_min_cpu = th_base_at_w_cpu.min();
                auto th_base_at_w_max_cpu = th_base_at_w_cpu.max();
                bool t_at_w_has_nan = t_at_w_has_nan_cpu.item<bool>();
                bool t_at_w_has_inf = t_at_w_has_inf_cpu.item<bool>();
