                // PERF FIX 2025-12-28: Pre-compute reductions with _cpu suffix
                auto t_full_at_w_has_nan_cpu = t_full_at_w_cpu.isnan().any();
                auto t_full_at_w_has_inf_cpu = t_full_at_w_cpu.isinf().any();
                auto t_full_at_w_min_cpu = t_full_at_w_cpu.min();
                auto t_full_at_w_max_cpu = t_full_at_w_cpu.max();
                bool t_full_at_w_has_nan = t_full_at_w_has_nan_cpu.item<bool>();
