            // W-MOMENTUM PGF PRESSURE:
            // WRF Fortran pg_buoy_w (L2419-2499) uses PERTURBATION pressure p, NOT full pressure.
            // Formula: cq1*rdn(k)*(p(i,k,j)-p(i,k-1,j)) - c1f*muf - cq2*(c1f*mubf+c2f)
            // p_pert_mass at mass-levels is the correct input (computed via hydrostatic integration)
            torch::Tensor p_pert_w, p_base_at_w, p_full_w;

            // Always compute p_base_at_w (needed for full pressure)
            p_base_at_w = avg_z_to_w(p_base_);

